body.script:
const MODEL_URL = 'https://cdn.jsdelivr.net/npm/@vladmandic/face-api/model';
const video = document.getElementById('video');
const canvas = document.getElementById('overlay');
const statusEl = document.getElementById('status');
const noFaceEl = document.getElementById('no-face');
let detecting = false;
let currentEmotion = 'neutral';

function setStatus(msg) { statusEl.textContent = msg; }

async function startCamera() {
  document.getElementById('start-btn').style.display = 'none';
  setStatus('LOADING NEURAL MODELS…');
  try {
    await faceapi.nets.tinyFaceDetector.loadFromUri(MODEL_URL);
    await faceapi.nets.faceExpressionNet.loadFromUri(MODEL_URL);
    setStatus('MODELS LOADED ✓  REQUESTING CAMERA…');
    const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' }, audio: false });
    video.srcObject = stream;
    video.onloadedmetadata = () => { canvas.width = 462; canvas.height = 356; detectLoop(); setStatus(''); };
  } catch(e) {
    setStatus('ERROR: ' + e.message);
  }
}

async function detectLoop() {
  const ctx = canvas.getContext('2d');
  const opts = new faceapi.TinyFaceDetectorOptions({ inputSize: 224, scoreThreshold: 0.5 });

  async function tick() {
    ctx.clearRect(0, 0, 462, 356);
    const detections = await faceapi.detectAllFaces(video, opts).withFaceExpressions();

    if (detections.length === 0) {
      noFaceEl.style.display = 'flex';
      broadcastEmotion('none');
    } else {
      noFaceEl.style.display = 'none';
      detections.forEach(det => {
        const box = det.detection.box;
        // Flip for mirrored canvas
        const x = 462 - box.x - box.width;

        // Face bounding box
        ctx.strokeStyle = '#00ffb4';
        ctx.lineWidth = 2;
        ctx.shadowColor = '#00ffb4';
        ctx.shadowBlur = 8;
        ctx.strokeRect(x, box.y, box.width, box.height);
        ctx.shadowBlur = 0;

        // Corner ticks
        const t = 14;
        ctx.lineWidth = 3;
        ctx.strokeStyle = '#00ffb4';
        [[x,box.y],[x+box.width,box.y],[x,box.y+box.height],[x+box.width,box.y+box.height]].forEach(([cx,cy],i) => {
          ctx.beginPath();
          ctx.moveTo(cx + (i%2===0?t:-t), cy); ctx.lineTo(cx, cy); ctx.lineTo(cx, cy + (i<2?t:-t));
          ctx.stroke();
        });

        // Top label
        const topEmotion = Object.entries(det.expressions).sort((a,b)=>b[1]-a[1])[0];
        const label = topEmotion[0].toUpperCase();
        const conf = Math.round(topEmotion[1]*100);
        ctx.fillStyle = '#00ffb4';
        ctx.font = 'bold 11px Courier New';
        ctx.shadowColor = '#00ffb4'; ctx.shadowBlur = 6;
        ctx.fillText(`${label}  ${conf}%`, x, box.y > 16 ? box.y - 6 : box.y + 14);
        ctx.shadowBlur = 0;

        // Broadcast
        broadcastEmotion(topEmotion[0]);

        // Confidence bars
        const emotions = Object.entries(det.expressions).sort((a,b)=>b[1]-a[1]).slice(0,3);
        emotions.forEach(([em, conf2], idx) => {
          const bx = x, by = box.y + box.height + 6 + idx * 14;
          ctx.fillStyle = 'rgba(0,255,180,0.15)';
          ctx.fillRect(bx, by, box.width, 10);
          ctx.fillStyle = '#00ffb4';
          ctx.fillRect(bx, by, box.width * conf2, 10);
          ctx.fillStyle = '#fff';
          ctx.font = '8px Courier New';
          ctx.fillText(em.slice(0,3).toUpperCase() + ' ' + Math.round(conf2*100)+'%', bx+2, by+8);
        });
      });
    }
    requestAnimationFrame(tick);
  }
  tick();
}

function broadcastEmotion(emotion) {
  if (emotion !== currentEmotion) {
    currentEmotion = emotion;
    // Post to parent SVG via custom event on window
    window.dispatchEvent(new CustomEvent('emotionDetected', { detail: emotion }));
    // Also try parent
    try { window.parent.dispatchEvent(new CustomEvent('emotionDetected', { detail: emotion })); } catch(e) {}
    // Update SVG element directly
    try {
      const svgDoc = window.frameElement ? window.frameElement.ownerDocument : document;
      const el = svgDoc.getElementById('emotion-display');
      if (el) el.setAttribute('data-emotion', emotion);
      // Trigger visibility on SVG emotion faces
      ['happy','sad','angry','surprised','disgusted','fearful','neutral'].forEach(e => {
        const face = svgDoc.getElementById('face-' + e);
        if (face) face.style.opacity = (e === emotion) ? '1' : '0.18';
      });
      const lbl = svgDoc.getElementById('emotion-label');
      if (lbl) lbl.textContent = emotion === 'none' ? '— SCANNING —' : emotion.toUpperCase();
    } catch(ex) {}
  }
}

svg.script:

// Listen for emotion events bubbled from foreignObject iframe
window.addEventListener('emotionDetected', function(e) {
  const emotion = e.detail;
  const emotions = ['happy','sad','angry','surprised','disgusted','fearful','neutral'];
  emotions.forEach(function(em) {
    var el = document.getElementById('face-' + em);
    if (el) el.style.opacity = (em === emotion) ? '1' : '0.18';
  });
  var lbl = document.getElementById('emotion-label');
  if (lbl) lbl.textContent = emotion === 'none' ? '— SCANNING —' : emotion.toUpperCase();
});
